diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 6e4689863407..a6eb3225d891 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1317,6 +1317,7 @@ static Value *foldAndOrOfICmpsWithConstEq(ICmpInst *Cmp0, ICmpInst *Cmp1,
 /// or   (icmp Pred1 V1, C1) | (icmp Pred2 V2, C2)
 /// into a single comparison using range-based reasoning.
 /// NOTE: This is also used for logical and/or, must be poison-safe!
+
 Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
                                                      ICmpInst *ICmp2,
                                                      bool IsAnd) {
@@ -1338,9 +1339,30 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       V2 = X;
   }

-  if (V1 != V2)
+  // Also look through AND operations to find common base values
+  Value *BaseV1 = V1, *BaseV2 = V2;
+  const APInt *Mask1 = nullptr, *Mask2 = nullptr;
+  if (match(V1, m_And(m_Value(BaseV1), m_APInt(Mask1))) &&
+      match(V2, m_And(m_Value(BaseV2), m_APInt(Mask2)))) {
+    // Both have AND, check if they have the same base
+    if (BaseV1 != BaseV2)
+      return nullptr;
+  } else if (match(V1, m_And(m_Value(BaseV1), m_APInt(Mask1)))) {
+    // Only V1 has AND
+    if (BaseV1 != V2)
+      return nullptr;
+    BaseV2 = BaseV1;
+  } else if (match(V2, m_And(m_Value(BaseV2), m_APInt(Mask2)))) {
+    // Only V2 has AND
+    if (BaseV2 != V1)
+      return nullptr;
+    BaseV1 = BaseV2;
+  }
+
+  if (BaseV1 != BaseV2)
     return nullptr;

+  // Now compute ranges for the comparisons
   ConstantRange CR1 = ConstantRange::makeExactICmpRegion(
       IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
   if (Offset1)
@@ -1351,25 +1373,58 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   if (Offset2)
     CR2 = CR2.subtract(*Offset2);

-  Type *Ty = V1->getType();
-  Value *NewV = V1;
+  // If we have masked comparisons, adjust the ranges
+  if (Mask1) {
+    // For (X & Mask) == C, the valid X values are in the range
+    // [C, C + (~Mask + 1)) with stride 1
+    APInt MaskVal = *Mask1;
+    APInt MaskComplement = ~MaskVal + 1;
+    APInt CR1Lower = CR1.getLower();
+    APInt CR1Upper = CR1.getUpper();
+    // Expand the range to account for masked bits
+    CR1 = ConstantRange(CR1Lower, CR1Lower + MaskComplement);
+  }
+  
+  if (Mask2) {
+    APInt MaskVal = *Mask2;
+    APInt MaskComplement = ~MaskVal + 1;
+    APInt CR2Lower = CR2.getLower();
+    APInt CR2Upper = CR2.getUpper();
+    CR2 = ConstantRange(CR2Lower, CR2Lower + MaskComplement);
+  }
+
+  Type *Ty = BaseV1->getType();
+  Value *NewV = BaseV1;
   std::optional<ConstantRange> CR = CR1.exactUnionWith(CR2);
   if (!CR) {
     if (!(ICmp1->hasOneUse() && ICmp2->hasOneUse()) || CR1.isWrappedSet() ||
         CR2.isWrappedSet())
       return nullptr;

-    // Check whether we have equal-size ranges that only differ by one bit.
-    // In that case we can apply a mask to map one range onto the other.
-    APInt LowerDiff = CR1.getLower() ^ CR2.getLower();
-    APInt UpperDiff = (CR1.getUpper() - 1) ^ (CR2.getUpper() - 1);
-    APInt CR1Size = CR1.getUpper() - CR1.getLower();
-    if (!LowerDiff.isPowerOf2() || LowerDiff != UpperDiff ||
-        CR1Size != CR2.getUpper() - CR2.getLower())
+    // Check whether we have ranges that can be combined
+    // For our test case: CR1 = [127, 128), CR2 = [128, 160)
+    // These are adjacent and can be combined to [127, 160)
+    if (CR1.getUpper() == CR2.getLower() || CR2.getUpper() == CR1.getLower()) {
+      APInt NewLower = CR1.getLower().ult(CR2.getLower()) ? 
+                       CR1.getLower() : CR2.getLower();
+      APInt NewUpper = CR1.getUpper().ugt(CR2.getUpper()) ?
+                       CR1.getUpper() : CR2.getUpper();
+      CR = ConstantRange(NewLower, NewUpper);
+    } else {
+      // Try the original mask logic for power-of-two differences
+      APInt LowerDiff = CR1.getLower() ^ CR2.getLower();
+      APInt UpperDiff = (CR1.getUpper() - 1) ^ (CR2.getUpper() - 1);
+      APInt CR1Size = CR1.getUpper() - CR1.getLower();
+      APInt CR2Size = CR2.getUpper() - CR2.getLower();
+      if (LowerDiff.isPowerOf2() && LowerDiff == UpperDiff &&
+          CR1Size == CR2Size) {
+        CR = CR1.getLower().ult(CR2.getLower()) ? CR1 : CR2;
+        NewV = Builder.CreateAnd(NewV, ConstantInt::get(Ty, ~LowerDiff));
+      }
+    }
+    
+    if (!CR)
       return nullptr;
-
-    CR = CR1.getLower().ult(CR2.getLower()) ? CR1 : CR2;
-    NewV = Builder.CreateAnd(NewV, ConstantInt::get(Ty, ~LowerDiff));
   }

   if (IsAnd)
@@ -1384,6 +1439,7 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
 }

